INSERT INTO `combos` VALUES (1,'Mega Sweet Combo','mega-sweet-combo','A delightful mix of our premium Karadant and Laddu.','karadant',1200.00,'assets/images/combos/karadant-combo.png',1,'2026-04-30 10:40:44'),(2,'Festive Namkeen Mix','festive-namkeen-mix','Spicy and crunchy namkeen assortment.','namkeen',450.00,'assets/images/combos/namkeen-combo.png',1,'2026-04-30 10:40:44'),(3,'Premium Laddu Box','premium-laddu-box','The best selection of assorted laddus.','laddu',800.00,'assets/images/combos/laddu-combo.png',1,'2026-04-30 10:40:44'),(4,'Family Festival Pack','family-festival-pack','Something for everyone in the family.','karadant',2500.00,'assets/images/combos/family-combo.png',1,'2026-04-30 10:40:44'),(5,'Classic Karadant Pair','classic-karadant-pair','Two of our best selling Karadants.','karadant',1100.00,'assets/images/combos/classic-karadant.png',1,'2026-04-30 10:40:44'),(6,'Healthy Bites','healthy-bites','Nutritious Ragi Laddu and Dink Karadant.','karadant',900.00,'assets/images/combos/healthy-bites.png',1,'2026-04-30 10:40:44'),(7,'Ultimate Gift Box','ultimate-gift-box','The perfect gift for any occasion.','gifting',3000.00,'assets/images/combos/gifting-combo.png',1,'2026-04-30 10:40:44'),(8,'Mini Snack Pack','mini-snack-pack','A small pack of joy.','namkeen',300.00,'assets/images/combos/mini-snack.png',1,'2026-04-30 10:40:44'),(9,'demo','demo','dagasagaASFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF','karadant',500.00,'assets/images/combos/sw_69f3408e6fa7a3.23596280.png',1,'2026-04-30 11:44:14'),(10,'laddu','laddu','bfnfgmfgznsfbksdbklshdblsdzkbskldbsldzfbdbsdbsdb','laddu',800.00,'assets/images/combos/sw_69f34e9c3f2a59.46823182.png',1,'2026-04-30 12:44:12'),(11,'Premium Traditional Combo 01','premium-traditional-combo-01','A curated selection of our finest traditional sweets.','laddu',999.00,'assets/images/combo-offer/combo-offer-01.jpeg',1,'2026-05-02 10:46:54'),(12,'Festive Family Pack 02','festive-family-pack-02','Perfect for sharing with the whole family during celebrations.','gifting',1499.00,'assets/images/combo-offer/combo-offer-02.jpeg',1,'2026-05-02 10:46:54'),(13,'Gourmet Sweet Assortment 03','gourmet-sweet-assortment-03','Indulge in a variety of gourmet sweet flavors.','karadant',1299.00,'assets/images/combo-offer/combo-offer-03.jpeg',1,'2026-05-02 10:46:54'),(14,'Luxury Celebration Box 04','luxury-celebration-box-04','Our most luxurious sweets in one elegant package.','gifting',1999.00,'assets/images/combo-offer/combo-offer-04.jpeg',1,'2026-05-02 10:46:54'),(15,'Artisanal Karadant Selection 05','artisanal-karadant-selection-05','Traditional Karadant made with artisanal care.','karadant',899.00,'assets/images/combo-offer/combo-offer-05.jpeg',1,'2026-05-02 10:46:54'),(16,'Classic Sweet Duo 06','classic-sweet-duo-06','Two of our most loved sweet treats in one pack.','karadant',599.00,'assets/images/combo-offer/combo-offer-06.jpeg',1,'2026-05-02 10:46:54'),(17,'Health-Conscious Sweet Mix 07','health-conscious-sweet-mix-07','Sweets made with healthy ingredients and minimal sugar.','laddu',1099.00,'assets/images/combo-offer/combo-offer-07.jpeg',1,'2026-05-02 10:46:54'),(18,'Royal Sweet Platter 08','royal-sweet-platter-08','A platter fit for royalty, featuring assorted delicacies.','gifting',2499.00,'assets/images/combo-offer/combo-offer-08.jpeg',1,'2026-05-02 10:46:54'),(19,'Grand Festival Combo 09','grand-festival-combo-09','Celebrate in grand style with this massive combo pack.','gifting',2999.00,'assets/images/combo-offer/combo-offer-09.jpeg',1,'2026-05-02 10:46:54'),(20,'Signature Sweet Box 10','signature-sweet-box-10','Our signature sweets, hand-picked for perfection.','karadant',1199.00,'assets/images/combo-offer/combo-offer-10.jpeg',1,'2026-05-02 10:46:54'),(21,'Traditional Delights 11','traditional-delights-11','Delightful traditional sweets for every occasion.','karadant',799.00,'assets/images/combo-offer/combo-offer-11.jpeg',1,'2026-05-02 10:46:54'),(22,'Sweet Heritage Pack 12','sweet-heritage-pack-12','Experience the rich heritage of our traditional recipes.','karadant',1399.00,'assets/images/combo-offer/combo-offer-12.jpeg',1,'2026-05-02 10:46:54'),(23,'Premium Laddu Mix 13','premium-laddu-mix-13','An assortment of our premium laddus.','laddu',849.00,'assets/images/combo-offer/combo-offer-13.jpeg',1,'2026-05-02 10:46:54'),(24,'Crunchy Namkeen Combo 14','crunchy-namkeen-combo-14','A mix of our best selling namkeen and snacks.','namkeen',649.00,'assets/images/combo-offer/combo-offer-14.jpeg',1,'2026-05-02 10:46:54'),(25,'Sweet & Spicy Pair 15','sweet-and-spicy-pair-15','The perfect balance of sweet treats and spicy snacks.','gifting',899.00,'assets/images/combo-offer/combo-offer-15.jpeg',1,'2026-05-02 10:46:54'),(26,'Corporate Gifting Pack 16','corporate-gifting-pack-16','Elegant packaging and premium taste, ideal for gifting.','gifting',1599.00,'assets/images/combo-offer/combo-offer-16.jpeg',1,'2026-05-02 10:46:54'),(27,'Homecoming Special 17','homecoming-special-17','A warm welcome with our most nostalgic sweets.','karadant',1249.00,'assets/images/combo-offer/combo-offer-17.jpeg',1,'2026-05-02 10:46:54'),(28,'Evening Snack Mix 18','evening-snack-mix-18','Perfect accompaniments for your evening tea.','namkeen',549.00,'assets/images/combo-offer/combo-offer-18.jpeg',1,'2026-05-02 10:46:54'),(29,'Bestseller Combo 19','bestseller-combo-19','A collection of our top 5 best selling items.','karadant',1799.00,'assets/images/combo-offer/combo-offer-19.jpeg',1,'2026-05-02 10:46:54'),(30,'Chef Special Selection 20','chef-special-selection-20','Hand-crafted selection by our master chefs.','karadant',2199.00,'assets/images/combo-offer/combo-offer-20.jpeg',1,'2026-05-02 10:46:54'),(31,'karkant','karkant','WEGEGWEGWEGWEGWEWE','laddu',500.00,'assets/images/combos/sw_69f5fde39d97c2.91285080.png',1,'2026-05-02 13:36:35');
